   117	  });
   118	  const payload = await response.json();
   119	  if (!response.ok || payload?.ok === false) {
   120	    throw new Error(`Failed to create auth session: ${payload?.error || response.status}`);
   121	  }
   122	  const setCookie = response.headers.get('set-cookie');
   123	  if (!setCookie) {
