   132	async function createClient(t, port, cookie) {
   133	  const ws = new WebSocket(`ws://127.0.0.1:${port}/ws`, {
   134	    headers: cookie ? { Cookie: cookie } : undefined,
   135	  });
   136	  const messages = [];
   137	
   138	  ws.on('message', (data) => {
   139	    try {
   140	      messages.push(JSON.parse(data.toString()));
   141	    } catch {
   142	      // ignore malformed frames
   143	    }
   144	  });
   145	
   146	  await once(ws, 'open');
   147	
   148	  t.after(() => {
   149	    if (ws.readyState === WebSocket.OPEN || ws.readyState === WebSocket.CONNECTING) {
   150	      ws.terminate();
   151	    }
   152	  });
   153	
   154	  return {
   155	    ws,
   156	    messages,
   157	    send(payload) {
   158	      ws.send(JSON.stringify(payload));
   159	    },
   160	    latestState() {
   161	      for (let i = messages.length - 1; i >= 0; i -= 1) {
   162	        if (messages[i].type === 'state') return messages[i];
   163	      }
   164	      return null;
   165	    },
   166	  };
   167	}
