   169	async function waitForMessage(client, predicate, label, timeoutMs = 5000) {
   170	  return waitFor(() => {
   171	    const message = client.messages.find(predicate);
   172	    if (message) return message;
   173	    return null;
   174	  }, timeoutMs).catch(() => {
   175	    const last = client.messages.at(-1);
   176	    throw new Error(`Timeout waiting for "${label}". Last message: ${JSON.stringify(last)}`);
   177	  });
   178	}
